%  Вычисляет невязку системы уравнений

function y = nonlinear_equations_system_full(x, n, arr)
    y = zeros(4 * size(arr, 1) - 1, 1);
    %  начальные условия по кинетической энергии из графика
    y(1:3, 1) = [0.5*sum((A(0, x, n, 1) .* x(1:n) .*           cos(x((3*n+1):(4*n))) + A1(0, x, n, 1) .* sin(x((3*n+1):(4*n)))).^2) - arr(1, 1);
                 0.5*sum((A(0, x, n, 2) .* x((n+1):(2*n)) .*   cos(x((4*n+1):(5*n))) + A1(0, x, n, 2) .* sin(x((4*n+1):(5*n)))).^2) - arr(1, 2);
                 0.5*sum((A(0, x, n, 3) .* x((2*n+1):(3*n)) .* cos(x((5*n+1):(6*n))) + A1(0, x, n, 3) .* sin(x((5*n+1):(6*n)))).^2) - arr(1, 3)];

    for t_id = 0:(size(arr, 1) - 1)  %  кинетика полной энергии
        t = t_id;
        y((1:3) + 3 * (t_id + 1), 1) = [...
            0.5 * sum(2 * A(t, x, n, 1) .* A1(t, x, n, 1) .*     (x(1:n).^2) ...
            +            A1(t, x, n, 1).^2 .*                     x(1:n) .*               sin(2*(x(1:n) *           t + x((3*n+1):(4*n)))) ...
            +             A(t, x, n, 1) .* A2(t, x, n, 1) .*      x(1:n) .*               sin(2*(x(1:n) *           t + x((3*n+1):(4*n)))) ...
            +         2 * A(t, x, n, 1) .* A1(t, x, n, 1) .*     (x(1:n).^2) .*           cos(2*(x(1:n) *           t + x((3*n+1):(4*n)))) ...
            +        2 * A1(t, x, n, 1) .* A2(t, x, n, 1) .*                             (sin(   x(1:n) *           t + x((3*n+1):(4*n))).^2) ...
            +            A1(t, x, n, 1).^2 .*                     x(1:n) .*               sin(2*(x(1:n) *           t + x((3*n+1):(4*n))))) ...
            - x(6*n+4) *              0.5 * sum((A(t, x, n, 2) .* x((n+1):(2*n)) .*       cos(   x((n+1):(2*n)) *   t + x((4*n+1):(5*n))) + A1(t, x, n, 2) .* sin(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))).^2 + (A(t, x, n, 2) .* x((n+1):(2*n)) .*   cos(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))).^2) ...
            - x(6*n+3) *              0.5 * sum((A(t, x, n, 3) .* x((2*n+1):(3*n)) .*     cos(   x((2*n+1):(3*n)) * t + x((5*n+1):(6*n))) + A1(t, x, n, 3) .* sin(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))).^2 + (A(t, x, n, 3) .* x((2*n+1):(3*n)) .* cos(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))).^2) ...
            + (x(6*n+1) + x(6*n+6)) * 0.5 * sum((A(t, x, n, 1) .* x(1:n) .*               cos(   x(1:n) *           t + x((3*n+1):(4*n))) + A1(t, x, n, 1) .* sin(x(1:n) *           t + x((3*n+1):(4*n)))).^2 + (A(t, x, n, 1) .* x(1:n) .*           cos(x(1:n) *           t + x((3*n+1):(4*n)))).^2);

            0.5 * sum(2 * A(t, x, n, 2) .* A1(t, x, n, 2) .*     (x((n+1):(2*n)).^2) ...
            +            A1(t, x, n, 2).^2 .*                     x((n+1):(2*n)) .*       sin(2*(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))) ...
            +             A(t, x, n, 2) .* A2(t, x, n, 2) .*      x((n+1):(2*n)) .*       sin(2*(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))) ...
            +         2 * A(t, x, n, 2) .* A1(t, x, n, 2) .*     (x((n+1):(2*n)).^2) .*   cos(2*(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))) ...
            +        2 * A1(t, x, n, 2) .* A2(t, x, n, 2) .*                             (sin(   x((n+1):(2*n)) *   t + x((4*n+1):(5*n))).^2) ...
            +            A1(t, x, n, 2).^2 .*                     x((n+1):(2*n)) .*       sin(2*(x((n+1):(2*n)) *   t + x((4*n+1):(5*n))))) ...
            - x(6*n+1) *              0.5 * sum((A(t, x, n, 1) .* x(1:n) .*               cos(   x(1:n) *           t + x((3*n+1):(4*n))) + A1(t, x, n, 1) .* sin(x(1:n) *           t + x((3*n+1):(4*n)))).^2 + (A(t, x, n, 1) .* x(1:n) .*           cos(x(1:n) *           t + x((3*n+1):(4*n)))).^2) ...
            - x(6*n+5) *              0.5 * sum((A(t, x, n, 3) .* x((2*n+1):(3*n)) .*     cos(   x((2*n+1):(3*n)) * t + x((5*n+1):(6*n))) + A1(t, x, n, 3) .* sin(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))).^2 + (A(t, x, n, 3) .* x((2*n+1):(3*n)) .* cos(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))).^2) ...
            + (x(6*n+2) + x(6*n+4)) * 0.5 * sum((A(t, x, n, 2) .* x((n+1):(2*n)) .*       cos(   x((n+1):(2*n)) *   t + x((4*n+1):(5*n))) + A1(t, x, n, 2) .* sin(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))).^2 + (A(t, x, n, 2) .* x((n+1):(2*n)) .*   cos(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))).^2);

            0.5 * sum(2 * A(t, x, n, 3) .* A1(t, x, n, 3) .*     (x((2*n+1):(3*n)).^2) ...
            +            A1(t, x, n, 3).^2 .*                     x((2*n+1):(3*n)) .*     sin(2*(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))) ...
            +             A(t, x, n, 3) .* A2(t, x, n, 3) .*      x((2*n+1):(3*n)) .*     sin(2*(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))) ...
            +         2 * A(t, x, n, 3) .* A1(t, x, n, 3) .*     (x((2*n+1):(3*n)).^2) .* cos(2*(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))) ...
            +        2 * A1(t, x, n, 3) .* A2(t, x, n, 3) .*                             (sin(   x((2*n+1):(3*n)) * t + x((5*n+1):(6*n))).^2) ...
            +            A1(t, x, n, 3).^2 .*                    x((2*n+1):(3*n)) .*      sin(2*(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n))))) ...
            - x(6*n+6) *              0.5 * sum((A(t, x, n, 1) .* x(1:n) .*               cos(   x(1:n) *           t + x((3*n+1):(4*n))) + A1(t, x, n, 1) .* sin(x(1:n) *           t + x((3*n+1):(4*n)))).^2 + (A(t, x, n, 1) .* x(1:n) .*           cos(x(1:n) *           t + x((3*n+1):(4*n)))).^2) ...
            - x(6*n+2) *              0.5 * sum((A(t, x, n, 2) .* x((n+1):(2*n)) .*       cos(   x((n+1):(2*n)) *   t + x((4*n+1):(5*n))) + A1(t, x, n, 2) .* sin(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))).^2 + (A(t, x, n, 2) .* x((n+1):(2*n)) .*   cos(x((n+1):(2*n)) *   t + x((4*n+1):(5*n)))).^2) ...
            + (x(6*n+3) + x(6*n+5)) * 0.5 * sum((A(t, x, n, 3) .* x((2*n+1):(3*n)) .*     cos(   x((2*n+1):(3*n)) * t + x((5*n+1):(6*n))) + A1(t, x, n, 3) .* sin(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))).^2 + (A(t, x, n, 3) .* x((2*n+1):(3*n)) .* cos(x((2*n+1):(3*n)) * t + x((5*n+1):(6*n)))).^2)];
    end

    for t_id = 1:(size(arr, 1) - 1)  %    закон сохранения полной энергии, приравниваем к t==0
        t = t_id;
        y(3 * size(arr, 1) + t_id, 1) = 0.5 * (...
            sum((A(t, x, n, 1) .*                     x(1:n)).^2 ...
            +    A(t, x, n, 1) .*   A1(t, x, n, 1) .* x(1:n) .*             sin(2*(x(1:n) .* t + x((3*n+1):(4*n)))) ...
            +  (A1(t, x, n, 1) .*                                           sin(   x(1:n) .* t + x((3*n+1):(4*n)))).^2) ...
            ...
            + sum((A(t, x, n, 2) .*                   x((n+1):(2*n))).^2 ...
            +      A(t, x, n, 2) .* A1(t, x, n, 2) .* x((n+1):(2*n)) .*     sin(2*(x((n+1):(2*n)) .* t + x((4*n+1):(5*n)))) ...
            +    (A1(t, x, n, 2) .*                                         sin(   x((n+1):(2*n)) .* t + x((4*n+1):(5*n)))).^2) ...
            ...
            + sum((A(t, x, n, 3) .*                   x((2*n+1):(3*n))).^2 ...
            +      A(t, x, n, 3) .* A1(t, x, n, 3) .* x((2*n+1):(3*n)) .*   sin(2*(x((2*n+1):(3*n)) .* t + x((5*n+1):(6*n)))) ...
            +    (A1(t, x, n, 3) .*                                         sin(   x((2*n+1):(3*n)) .* t + x((5*n+1):(6*n)))).^2) ...
            ...
            - sum((A(0, x, n, 1) .*                   x(1:n)).^2 ...
            +      A(0, x, n, 1) .* A1(0, x, n, 1) .* x(1:n) .*             sin(2*x((3*n+1):(4*n))) ...
            +    (A1(0, x, n, 1) .*                                         sin(  x((3*n+1):(4*n)))).^2) ...
            ...
            - sum((A(0, x, n, 2) .*                   x((n+1):(2*n))).^2 ...
            +      A(0, x, n, 2) .* A1(0, x, n, 2) .* x((n+1):(2*n)) .*     sin(2*x((4*n+1):(5*n))) ...
            +    (A1(0, x, n, 2) .*                                         sin(  x((4*n+1):(5*n)))).^2) ...
            ...
            - sum((A(0, x, n, 3) .*                   x((2*n+1):(3*n))).^2 ...
            +      A(0, x, n, 3) .* A1(0, x, n, 3) .* x((2*n+1):(3*n)) .*   sin(2*x((5*n+1):(6*n))) ...
            +    (A1(0, x, n, 3) .*                                         sin(  x((5*n+1):(6*n)))).^2));
    end
end